import React from "react";

import {
  MapContainer,
  TileLayer,
  Marker,
  Popup
} from "react-leaflet";

import "leaflet/dist/leaflet.css";

function MapView({ lat, lng, name }) {

  return (

    <MapContainer
      center={[lat, lng]}
      zoom={10}
      style={{
        height: "300px",
        width: "100%"
      }}
    >

      <TileLayer
        url="https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png"
      />

      <Marker position={[lat, lng]}>

        <Popup>
          {name}
        </Popup>

      </Marker>

    </MapContainer>
  );
}

export default MapView;
